import java.util.*;
public class BoundedQueue {
    private final int[] buffer;
    private int head = 0, tail = 0, count = 0;
    private final int capacity;

    public BoundedQueue(int capacity) {
        this.capacity = capacity;
        this.buffer = new int[capacity];
    }

    public synchronized void enqueue(int item) throws InterruptedException {
        while (count == capacity) wait();
        buffer[tail] = item;
        tail = (tail + 1) % capacity;
        count++;
        System.out.println("Enqueued: " + item);
        notifyAll();
    }

    public synchronized int dequeue() throws InterruptedException {
        while (count == 0) wait();
        int item = buffer[head];
        head = (head + 1) % capacity;
        count--;
        System.out.println("Dequeued: " + item);
        notifyAll();
        return item;
    }

    public static void main(String[] args) {
        BoundedQueue q = new BoundedQueue(3);
        new Thread(() -> { for (int i=1;i<=5;i++) { try { q.enqueue(i); Thread.sleep(100); } catch(Exception e){} } }).start();
        new Thread(() -> { for (int i=0;i<5;i++) { try { q.dequeue(); Thread.sleep(250); } catch(Exception e){} } }).start();
    }
}

import java.util.concurrent.*;
public class ParallelSum extends RecursiveTask<Long> {
    private static final int THRESHOLD = 10000;
    private final int[] array;
    private final int start, end;

    public ParallelSum(int[] array, int start, int end) {
        this.array = array; this.start = start; this.end = end;
    }

    @Override
    protected Long compute() {
        if (end - start <= THRESHOLD) {
            long sum = 0;
            for (int i = start; i < end; i++) sum += array[i];
            return sum;
        }
        int mid = (start + end) / 2;
        ParallelSum left = new ParallelSum(array, start, mid);
        ParallelSum right = new ParallelSum(array, mid, end);
        left.fork();
        return right.compute() + left.join();
    }

    public static void main(String[] args) {
        int n = 1000000;
        int[] array = new int[n];
        for (int i = 0; i < n; i++) array[i] = i + 1;
        ForkJoinPool pool = new ForkJoinPool();
        long result = pool.invoke(new ParallelSum(array, 0, n));
        System.out.println("Parallel Sum: " + result);
    }
}
